using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of numbers, structures, and mathematical reasoning." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Understanding the fundamental laws of nature and the universe." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events and their impact on the present." },
            new() { Id = 6, Code = "BIOL", Name = "Biology", Description = "Study of living organisms and life processes." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has over 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "A deep dive into essential data structures (lists, trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an expert in algorithm design with a focus on graph theory. He received his Ph.D. from Stanford and previously worked at Google Research." },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Introduction to relational database design, SQL, normalization, indexing, and transaction management. Includes a semester-long project building a database-driven application.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has over 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy." },
            new() { Id = 4, DepartmentId = 1, CourseCode = "CS 450", Title = "Machine Learning", Description = "Covers supervised and unsupervised learning, neural networks, decision trees, and model evaluation. Prerequisites: CS 201 and MATH 202.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Sarah Patel", InstructorBio = "Dr. Patel leads the university's AI research lab. Her work on natural language processing has been cited over 3,000 times.", IsFeatured = true },

            // Mathematics
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. James Liu", InstructorBio = "Dr. Liu is an award-winning mathematics educator who has taught calculus for over 20 years. He is the author of two widely adopted textbooks." },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH 202", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and computer graphics.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Maria Gonzalez", InstructorBio = "Dr. Gonzalez specializes in applied mathematics and has consulted for NASA on trajectory optimization problems.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 2, CourseCode = "MATH 301", Title = "Probability and Statistics", Description = "Probability distributions, statistical inference, hypothesis testing, and regression analysis with real-world data sets.", Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", InstructorName = "Dr. James Liu", InstructorBio = "Dr. Liu is an award-winning mathematics educator who has taught calculus for over 20 years. He is the author of two widely adopted textbooks." },

            // Physics
            new() { Id = 8, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. David Park", InstructorBio = "Dr. Park is a former researcher at CERN and brings real-world particle physics experience to the classroom." },
            new() { Id = 9, DepartmentId = 3, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. David Park", InstructorBio = "Dr. Park is a former researcher at CERN and brings real-world particle physics experience to the classroom.", IsFeatured = true },

            // English
            new() { Id = 10, DepartmentId = 4, CourseCode = "ENG 101", Title = "College Writing", Description = "Develop clear, effective writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Emily Brooks", InstructorBio = "Prof. Brooks is a published novelist and essayist who has taught writing at the university level for 12 years." },
            new() { Id = 11, DepartmentId = 4, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, including Hawthorne, Twain, Morrison, and contemporary voices.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a specialist in 20th-century American literature with a focus on multicultural narratives." },

            // History
            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "A survey of major civilizations, empires, and cultural developments from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", InstructorName = "Dr. Karen Wright", InstructorBio = "Dr. Wright has conducted archaeological research across Europe and the Middle East and is a leading voice in public history." },
            new() { Id = 13, DepartmentId = 5, CourseCode = "HIST 320", Title = "The Modern Middle East", Description = "Political, social, and cultural history of the Middle East from the Ottoman Empire to the present day.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", InstructorName = "Dr. Karen Wright", InstructorBio = "Dr. Wright has conducted archaeological research across Europe and the Middle East and is a leading voice in public history.", IsFeatured = true },

            // Biology
            new() { Id = 14, DepartmentId = 6, CourseCode = "BIOL 101", Title = "Introduction to Biology", Description = "Cell biology, genetics, evolution, and ecology. Includes lab component with microscopy and dissection.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Tue Lab 1:00–3:50 PM", InstructorName = "Dr. Natalie Okafor", InstructorBio = "Dr. Okafor is a molecular biologist whose research on gene therapy has been featured in Nature and Science.", IsFeatured = true },
            new() { Id = 15, DepartmentId = 6, CourseCode = "BIOL 305", Title = "Genetics and Genomics", Description = "Mendelian and molecular genetics, genome sequencing, CRISPR technology, and ethical considerations in genetic engineering.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", InstructorName = "Dr. Natalie Okafor", InstructorBio = "Dr. Okafor is a molecular biologist whose research on gene therapy has been featured in Nature and Science." }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course is null ? null : GetDepartment(course.DepartmentId);
    }

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

