@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments, explore courses, and submit your enrollment request.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in Catalog.GetFeaturedCourses())
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@dept?.Name · @course.Credits credits</h6>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in Catalog.GetDepartments())
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name (@dept.Code)</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="departments/@dept.Id" class="btn btn-outline-primary btn-sm">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

