@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit your enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId)?.Title)</strong> has been received.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm Model="Model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseSelect" class="form-label">Course</label>
                    <InputSelect id="courseSelect" @bind-Value="Model.CourseId" class="form-select">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Catalog.GetCourses())
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private bool submitted;

    protected override void OnInitialized()
    {
        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Catalog.SubmitEnrollment(Model);
        submitted = true;
    }
}

